from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregated_data = defaultdict(lambda: {
        "count": 0,
        "sum_scores": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf'),
        "custom_aggregations": {}
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None:
            group_value = "unknown"

        # Update statistics for this group
        group_stats = aggregated_data[group_value]

        # Update count and sum for average calculation
        group_stats["count"] += 1
        group_stats["sum_scores"] += result.score

        # Update max and min scores
        if result.score > group_stats["max_score"]:
            group_stats["max_score"] = result.score
        if result.score < group_stats["min_score"]:
            group_stats["min_score"] = result.score

    # Compute final statistics (average, etc.)
    for group_value, stats in aggregated_data.items():
        if stats["count"] > 0:
            stats["avg_score"] = stats["sum_scores"] / stats["count"]
        else:
            stats["avg_score"] = 0.0

        # Remove intermediate values we don't need to return
        del stats["sum_scores"]

    # Apply custom aggregation functions if provided
    if aggregation_funcs:
        for group_value, stats in aggregated_data.items():
            for field_name, func in aggregation_funcs.items():
                try:
                    # Get the values to aggregate from the search results
                    values = [
                        getattr(result, field_name, None) 
                        for result in search_results 
                        if result.metadata.get(group_by_field) == group_value
                    ]

                    # Filter out None values
                    values = [v for v in values if v is not None]

                    if values:
                        stats["custom_aggregations"][field_name] = func(values)
                    else:
                        stats["custom_aggregations"][field_name] = None
                except Exception as e:
                    # Log error but continue with None
                    stats["custom_aggregations"][field_name] = None

    # Convert defaultdict to regular dict for cleaner output
    final_result = {}
    for group_value, stats in aggregated_data.items():
        # Include both default and custom aggregations
        final_stats = {**stats, **stats.get("custom_aggregations", {})}
        # Remove the custom_aggregations key if it's empty
        if not final_stats.get("custom_aggregations"):
            final_stats.pop("custom_aggregations", None)
        final_result[group_value] = final_stats

    return final_result

